// generatedDrop returns the default item a block-state drops, if any.
func generatedDrop(state uint32) (int32, bool) {
	lo, hi := 0, len(blockDropRanges)-1
	for lo <= hi {
		mid := (lo + hi) / 2
		r := blockDropRanges[mid]
		switch {
		case state < r.Min:
			hi = mid - 1
		case state > r.Max:
			lo = mid + 1
		default:
			return r.Item, true
		}
	}
	return 0, false
}
